generated_oml:
// C2: Acting Components
instance MotorCurrentDriver : DTDFVocab:ActingComponent [
    base:desc "Controller current‑driver interface of the Siemens SINUMERIK 840D controller, enabling the Digital Twin to set motor current, position setpoints, and velocity for the robot’s permanent‑magnet synchronous motor."
]

// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor measuring electrical current flowing through the permanent‑magnet synchronous motor, providing real‑time data for torque estimation."
    DTDFVocab:producedData MotorCurrentTopic
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑side position encoder providing shaft angle of the motor shaft."
    DTDFVocab:producedData MotorEncoderTopic
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox‑side position encoder providing shaft angle of the gearbox output."
    DTDFVocab:producedData GearboxEncoderTopic
]

// C4: Physical‑to‑virtual interaction
instance MotorCurrentTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

// C10: Models/Data
instance TorqueCalculationModel : DTDFVocab:Model [
    base:desc "White‑box torque calculation model deriving torque from motor current and motor encoder data."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance AngularVelocityCalculationModel : DTDFVocab:Model [
    base:desc "White‑box angular velocity calculation model deriving speed from motor encoder data."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance MotorSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB® Simulink block representing the permanent‑magnet synchronous motor dynamics."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance GearwheelSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB® Simulink block representing the gearwheel dynamics with friction modules."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance GearboxSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB® Simulink block representing the cycloidal gearbox dynamics with friction modules."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Coulomb‑viscous friction model used in identification of static and kinetic friction components."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Stribeck friction model for smooth transition between static and kinetic friction."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance DahllFrictionModel : DTDFVocab:Model [
    base:desc "Dahl friction model capturing rate‑dependent friction behavior."
    DTDFVocab:inputTo DataProcessingEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "LuGre friction model providing a dynamic friction representation."
    DTDFVocab:inputTo DataProcessingEnabler
]

// C4: Data instances
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Raw motor current measurement transmitted over MQTT and used as input for torque calculation."
    DTDFVocab:fromData MotorCurrentTopic
    DTDFVocab:inputTo DataProcessingEnabler
]

instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Raw motor shaft angle measurement transmitted over MQTT and used for speed estimation."
    DTDFVocab:fromData MotorEncoderTopic
    DTDFVocab:inputTo DataProcessingEnabler
]

instance GearboxEncoderData : DTDFVocab:Data [
    base:desc "Raw gearbox output shaft angle measurement transmitted over MQTT and used for gearbox state monitoring."
    DTDFVocab:fromData GearboxEncoderTopic
    DTDFVocab:inputTo DataProcessingEnabler
]

// C11: Enablers
instance DataProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Processing component that consumes sensor data traces, runs calculation and simulation models, and provides updated parameters to the motion controller."
    DTDFVocab:enables RealTimeMonitoringService, FrictionIdentificationService, ModelUpdatingService, FrictionCompensationService, ParameterUpdateService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing metadata and identification for the Digital Twin assets."
    DTDFVocab:enables DataProcessingEnabler
]

// C13: Services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Real‑time monitoring and visualization of joint states delivered through a unified dashboard."
    DTDFVocab:provides DashboardVisualizationInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous multi‑physics‑aware identification of friction using combined white‑box and black‑box models."
    DTDFVocab:provides FrictionComponentShiftInsight
]

instance ModelUpdatingService : DTDFVocab:Service [
    base:desc "Dynamic model updating and friction compensation, providing friction parameter updates to the motion controller."
    DTDFVocab:provides FrictionParameterUpdateInsight
]

instance FrictionCompensationService : DTDFVocab:Service [
    base:desc "Friction compensation service that recommends control law adjustments."
    DTDFVocab:provides ControlLawAdjustmentInteraction
]

instance ParameterUpdateService : DTDFVocab:Service [
    base:desc "Provision of parameter updates to the motion controller and issuance of maintenance plans."
    DTDFVocab:provides MaintenancePlanInsight
] 

// C17: Insights/Actions
instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight rendering real‑time joint state visualization on the dashboard."
]

instance FrictionComponentShiftInsight : DTDFVocab:Insight [
    base:desc "Insight identifying shifts in static, kinetic, and viscous friction components."
]

instance FrictionParameterUpdateInsight : DTDFVocab:Insight [
    base:desc "Insight providing updated friction parameters derived from model mismatch."
]

instance MaintenancePlanInsight : DTDFVocab:Insight [
    base:desc "Insight informing maintenance plans based on wear indications derived from model mismatch."
]

instance ControlLawAdjustmentInteraction : DTDFVocab:Action [
    base:desc "Action recommending control law adjustments for friction compensation."
    DTDFVocab:IsAutomatic true
]

instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Action to update friction parameters in the motion controller."
    DTDFVocab:IsAutomatic true
]

instance AdjustControlLawAction : DTDFVocab:Action [
    base:desc "Action to adjust control law parameters based on friction identification."
    DTDFVocab:IsAutomatic true
]

instance IssueMaintenancePlanAction : DTDFVocab:Action [
    base:desc "Action to issue maintenance plan notifications."
    DTDFVocab:IsAutomatic true
]

// C6: Environment
instance MabiRobotEnvironment : DTDFVocab:Environment [
    base:contains MotorComponent, GearwheelComponent, CycloidalGearboxComponent, RobotJointComponent, SiemensControllerComponent
]

// C1: Components
instance MotorComponent : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first vertical axis of the MABI MAX 100 robot."
]

instance GearwheelComponent : DTDFVocab:Component [
    base:desc "Gearwheel gearbox component providing gear reduction for the motor shaft."
]

instance CycloidalGearboxComponent : DTDFVocab:Component [
    base:desc "Cycloidal gearbox component providing high‑torque reduction to the robot joint."
]

instance RobotJointComponent : DTDFVocab:Component [
    base:desc "Six‑axis joint in the MABI MAX 100 robot, first vertical axis driven by the motor and gearboxes."
]

instance SiemensControllerComponent : DTDFVocab:Component [
    base:desc "Siemens SINUMERIK 840D controller managing motor drives and receiving current‑driver interface from the Digital Twin."
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow is a passive digital shadow and does not issue commands or outputs back to the physical robot. Therefore, no virtual‑to‑physical data flow or actuation is implemented in this system."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "All data streams are forwarded in real time; the shadow continuously updates its simulations and friction‑model estimation at the native sensor rate (the exact sampling frequency is not specified in the document). The twin operates synchronously with the robot’s runtime data acquisition."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Architecture comprising a physical layer (robot, sensors, controller), a data ingestion layer (MQTT broker, AAS), a processing layer (simulation and calculation models executed by the processing component), and a presentation layer (dashboard). The DT is a digital shadow instantiated for the first axis and connected to the physical system via the AAS."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT represents the robot in the manufactured/operational phase, using a structural engineering model from the design stage and live operational data from the operational stage for continuous identification."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "White‑box friction models parameterized by load, temperature, wear; black‑box neural models learn residuals; continuous online identification ensures model fidelity; traceability of data points to originating source and processing step; validation by comparing simulated outputs (ˆr_M, ˆr_G, ˆr_out) with reference measured data (r_M, r_G, r_out)."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data is transmitted from the robot to the DT via MQTT messages that carry the encoder and current readings. The Asset Administration Shell (ISA‑95 compliant) provides a semantic endpoint for these messages. No push or command channel from the DT back to the robot is established, reflecting the shadow’s one‑way nature."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Uses SysML for structural modeling, Asset Administration Shells for standardised metadata, and references MBSE standards (RFLP, OOSEM, SPES, SMArDT)."
]
